  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '19', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', 'Notes on ordering-code rules captured', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '20', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '• SPAL / SPAS / SPAL-DUEB / SPAS-DUEB and AF take 2 thread codes (M = Metric ISO, U = Unified UNC) and 5 material codes (W1–W5).', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '21', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '• DPAL adds W85 (Aluminium EN AW-6060) — BUT only for STAUFF groups 3S–5S, per the catalogue footnote.', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '22', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '• DPAS has no W85 option documented — only W1–W5.', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '23', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '• AS (Hex Head Bolt) and IS (Socket Cap Screw) use 4 materials only: W1, W3, W4, W5. W2 is NOT a documented option for these.', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '24', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '• IS (Socket Cap Screw) is catalogued only for STAUFF groups 3S–6S (not the larger groups).', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '25', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '• SIP (Safety Locking Plate) and AF (Stacking Bolt) are catalogued only for STAUFF groups 3S–10S (not 11S/12S).', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '26', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '• AS and IS encode Thread×Length directly in the SKU (e.g. AS-M10x45-W1). Each group has a specific G×L pair.', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '27', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '• SI Safety Washers (DIN 93 and DIN 463) share a single SKU across multiple STAUFF groups when ØD1 is the same.', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '28', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '    Unique ØD1 values: 10.5 (groups 3S–5S), 13 (6S), 17 (7S), 21 (8S), 25 (9S), 31 (10S–12S).', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '29', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '    Materials limited to W3 and W5 only.', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '30', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '• Catalogue printing oddities preserved as notes on the affected rows:', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '31', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '    – Page 53 group 10S prints ''SIP-10-S-W1'' (extra dash). Canonical form ''SIP-10S-W1'' used.', NULL, NULL, NULL, NULL),
  ('STAUFF_pages_45_50_51_52_53_ordering_codes - Copy.xlsx', 'Overview', '32', 'STAUFF Clamps – Catalogue 1, pages 45 / 50 / 51 / 52 / 53', 'Heavy Series (DIN 3015, Part 2) — Weld plates, cover plates, bolts, washers, locking plate, stacking bolt', NULL, 'Permutations per page', '    – Page 51 group 6S Metric prints ''ISM12x80-W1'' (missing dash). Canonical form ''IS-M12x80-W1'' used.', NULL, NULL, NULL, NULL);
